const jwt = require('jsonwebtoken'); // Import the jsonwebToken module in NodeJS/Express 
require("dotenv").config();   // Load environment variables from .env file for JWT secret key and other sensitive data.

function authenticateJWT(req, res, next) {    // Define a function to handle authentication of the incoming requests with JSON Web Tokens (middleware). 
     const authHeader = req.headers['authorization'];   // Get 'Authorization' header from request headers if it exists or else return null and move on in middlewares chain otherwise, by default express will set this as undefined so we need to handle that case explicitly here too using conditional statement (if condition).
     const token = authHeader && authHeader.split(' ')[1];   // Split the header into two parts - "Bearer" and actual JWT Token which is stored in second part of array, if it exists or else return null 
     
    /* If no authorization headers are present then we can't authenticate */    
     if (!token) {   // Checking whether the token (JWT from header 'Authorization') exist. In case not existing ie., undefined/null, it will move to next middleware or route handler in Express app chain and return a 401 Unauthorized response back with an appropriate message
        return res.status(401).json({message: "Access Denied! No Token provided."});   // Returning the unauthorised status code alongwith error msg to client, if token not present in request headers then it will be handled by next middleware or route handler 
     }    /* End of checking for authorization header */     
      
        jwt.verify(token, process.env.ACCESS_TOKEN_SECRET , (err, decoded) => {   // Verifying the token using JWT's verify method with a secret key and callback function to handle errors if any occur during verification 
            /* If there is an error in verifying then return unauthorized status code alongwith appropriate message */   
             if (err){    
                console.log(`Error: ${err} `);   // Logging the err for debug purpose, you can remove this line after testing 
                 res.status(401).json({message:"Access Denied! Invalid Token."});      /* Returning unauthorized status code alongwith error message to client */   
             }else{    
                // If token is valid then proceed with the next middleware or route handler in Express app chain 
                 req.user = decoded;   // Decoding and storing user information into request object for further use, this can be used by other routes/middlewares as per requirement   
                  console.log(`User: ${decoded} `);     /* Logging the decode token data */ 
                 next();      // If no error found then move to handle requests at handler level in Express app chain  
             }      
        });/* End of JWT verification process*/   
};//End function authenticateJwtMiddleware() definition.    
